import React, {useState, useRef} from 'react';
import {
    Heart,
    Sparkles,
    Moon,
    Sun,
    Volume2,
    Zap,
    Calendar,
    Star,
    Smile,
    Coffee,
    Music,
    Flame,
    Cloud,
    Umbrella,
    Camera,
    Gift,
    Flower2,
    Feather,
    Palette,
    Rocket,
    Crown,
    Diamond,
    Cherry,
    Cake,
    IceCream,
    Pizza,
    Apple,
    Carrot,
    Cookie
} from 'lucide-react';
import IconPicker from "./Tools/IconPicker";

function ParamHeader() {
    const availableIcons = {
        Heart, Sparkles, Moon, Sun, Volume2, Zap, Calendar, Star, Smile, Coffee,
        Music, Flame, Cloud, Umbrella, Camera, Gift, Flower2, Feather, Palette,
        Rocket, Crown, Diamond, Cherry, Cake, IceCream, Pizza, Apple, Carrot, Cookie
    };

    const [params, setParams] = useState({
        brightness: 75,
        volume: 60,
        speed: 3,
        hearts: 5,
        sparkle: true,
        theme: 'pink',
        energy: 80,
        cuteness: 100,
        dateCount: 0,
        mood: null,
        pendingMood: null
    });

    const [paramIcons, setParamIcons] = useState({
        brightness: 'Sun',
        volume: 'Volume2',
        speed: 'Zap',
        hearts: 'Heart',
        sparkle: 'Sparkles',
        theme: 'Moon',
        energy: 'Zap',
        dateCount: 'Calendar',
        mood: 'Star'
    });

    const [iconPickerOpen, setIconPickerOpen] = useState(null);
    const [pickerPosition, setPickerPosition] = useState({top: 0, left: 0});
    const buttonRefs = useRef({});

    const updateParam = (key, value) => {
        setParams(prev => ({...prev, [key]: value}));
    };

    const updateIcon = (paramKey, iconName) => {
        setParamIcons(prev => ({...prev, [paramKey]: iconName}));
        setIconPickerOpen(null);
    };

    const handleDateClick = () => {
        updateParam('dateCount', params.dateCount + 1);
    };

    const handleIconClick = (paramKey) => {
        if (iconPickerOpen === paramKey) {
            setIconPickerOpen(null);
            return;
        }

        const button = buttonRefs.current[paramKey];
        if (button) {
            const rect = button.getBoundingClientRect();
            setPickerPosition({
                top: rect.bottom + window.scrollY + 8,
                left: rect.left + window.scrollX
            });
            setIconPickerOpen(paramKey);
        }
    };

    // 带图标选择器的标题组件
    const ParamHeader = ({paramKey, label, iconColor}) => {
        const IconComponent = availableIcons[paramIcons[paramKey]];
        return (
            <div className="flex items-center gap-2">
                <button
                    ref={(el) => buttonRefs.current[paramKey] = el}
                    onClick={() => handleIconClick(paramKey)}
                    className="group relative hover:scale-110 transition-transform"
                >
                    <IconComponent className={iconColor} size={20}/>
                    <div
                        className="absolute -top-1 -right-1 w-2 h-2 bg-pink-400 rounded-full opacity-0 group-hover:opacity-100 transition-opacity"/>
                </button>
                <span className="font-semibold text-gray-700">{label}</span>
            </div>
        );
    };

    return (
        <div
            className="min-h-screen flex items-center justify-center p-4 bg-gradient-to-br from-pink-50 via-purple-50 to-blue-50">

            {/* Date Counter */}
            <div className="bg-white/60 backdrop-blur-sm rounded-2xl p-4 shadow-lg">
                <div className="flex items-center justify-between">
                    <ParamHeader paramKey="dateCount" label="约会次数" iconColor="text-rose-500" buttonRefs={buttonRefs}/>
                    <div className="flex items-center gap-3">
                        <div className="flex items-center gap-1">
                            {[...Array(Math.min(params.dateCount, 5))].map((_, i) => (
                                <Heart
                                    key={i}
                                    className="text-rose-400 fill-rose-400 animate-pulse"
                                    size={16}
                                    style={{animationDelay: `${i * 0.1}s`}}
                                />
                            ))}
                        </div>
                        <span className="text-2xl font-bold text-rose-500 min-w-12 text-center">
              {params.dateCount}
            </span>
                        <button
                            onClick={handleDateClick}
                            className="group relative px-4 py-2 bg-gradient-to-r from-rose-400 to-pink-500 text-white font-bold rounded-xl hover:scale-110 active:scale-95 transition-all shadow-lg hover:shadow-xl"
                        >
                            <span className="relative z-10">+1</span>
                            <div
                                className="absolute inset-0 bg-gradient-to-r from-rose-500 to-pink-600 rounded-xl opacity-0 group-hover:opacity-100 transition-opacity"/>
                        </button>
                    </div>
                </div>
            </div>


            {/* 图标选择器 Portal */}
            {iconPickerOpen && (
                <IconPicker
                    paramKey={iconPickerOpen}
                    currentIcon={paramIcons[iconPickerOpen]}
                    onSelect={updateIcon}
                    onClose={() => setIconPickerOpen(null)}
                    position={pickerPosition}
                    buttonRefs={buttonRefs}
                />
            )}
        </div>
    );
}

export default ParamHeader;
